Part.Source:
//verifica id da sessao. verificaidsessao.Call(&DevRandon, &IsAcessoConcedido, &IsAtualizaTudo, &wwpContext)
if &IsAcessoConcedido = true //Acesso concedido For Each ORder EmpCod, FilCod, CteCod Where EmpCod = &wwpContext.EmpCod Where FilCod = &FilCod Where CteCod = &CteCod
&sdtCte.sts = 'J200' &sdtCte.obs = '' &sdtCte.CteModCod = CteModCod
&sdtCte.FilCod = FilCod &sdtCte.FilNom = FilNom &sdtCte.CteSts = CteSts
&sdtCte.CteFinEms = CteFinEms &sdtCte.CteTipSer = CteTipSer
&sdtCte.CteLctCod = CteLctCod For Each ORder EmpCod, LctCod Where LctCod = CteLctCod &sdtCte.CteLctNom = LctNom Exit When None For Each ORder EmpCod, LctCod &sdtCte.CteLctCod = LctCod &sdtCte.CteLctNom = LctNom Exit EndFor EndFor
//remetente &sdtCte.CteRemCod = CteRemCod if CteRemCnpj.IsEmpty() or CteRemCnpj.IsNull() &PesCnpj = CteRemCpf validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteRemCnpjCpf = format('CPF: %1', trim(&PesCnpj)) Else &PesCnpj = CteRemCnpj validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteRemCnpjCpf = format('CNPJ: %1', trim(&PesCnpj)) Endif
&sdtCte.CteRemRaz = CteRemRaz &sdtCte.CteRemCidCod = CteRemCidCod &sdtCte.CteRemCidNom = CteRemCidNom &sdtCte.CteRemUfe = CteRemUfe
//destinatario &sdtCte.CteDesCod = CteDesCod if CteDesCnpj.IsEmpty() or CteDesCnpj.IsNull() &PesCnpj = CteDesCpf validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteDesCnpjCpf = format('CPF: %1', trim(&PesCnpj)) Else &PesCnpj = CteDesCnpj validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteDesCnpjCpf = format('CNPJ: %1', trim(&PesCnpj)) Endif &sdtCte.CteDesRaz = CteDesRaz &sdtCte.CteDesCidCod = CteDesCidCod &sdtCte.CteDesCidNom = CteDesCidNom &sdtCte.CteDesUfe = CteDesUfe
//expedidor &sdtCte.CteExpCod = CteExpCod &sdtCte.CteExpRaz = CteExpRaz if CteExpCnpj.IsEmpty() or CteExpCnpj.IsNull() &PesCnpj = CteExpCpf validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteExpCnpjCpf = format('CPF: %1', trim(&PesCnpj)) Else &PesCnpj = CteExpCnpj validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteExpCnpjCpf = format('CNPJ: %1', trim(&PesCnpj)) Endif &sdtCte.CteExpCidCod = CteExpCidCod &sdtCte.CteExpCidNom = CteExpCidNom &sdtCte.CteExpUfe = CteExpUfe
//recebedor &sdtCte.CteRecCod = CteRecCod &sdtCte.CteRecRaz = CteRecRaz if CteRecCnpj.IsEmpty() or CteRecCnpj.IsNull() &PesCnpj = CteRecCpf validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteRecCnpjCpf = format('CPF: %1', trim(&PesCnpj)) Else &PesCnpj = CteRecCnpj validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteRecCnpjCpf = format('CNPJ: %1', trim(&PesCnpj)) Endif &sdtCte.CteRecCidCod = CteRecCidCod &sdtCte.CteRecCidNom = CteRecCidNom &sdtCte.CteRecUfe = CteRecUfe
//Tomador &sdtCte.CteTomCod = CteTomCod &sdtCte.CteTomRaz = CteTomRaz if CteTomCnpj.IsEmpty() or CteTomCnpj.IsNull() &PesCnpj = CteTomCpf validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteTomCnpjCpf = format('CPF: %1', trim(&PesCnpj)) Else &PesCnpj = CteTomCnpj validaCpfCnpj.call(&PesCnpj, &erro, 'N') &sdtCte.CteTomCnpjCpf = format('CNPJ: %1', trim(&PesCnpj)) Endif &sdtCte.CteTomCidCod = CteTomCidCod &sdtCte.CteTomCidNom = CteTomCidNom &sdtCte.CteTomUfe = CteTomUfe
//Tipo de responsavel frete if CteModCod = '57' &sdtCte.CteTomSer = CteTomSer Else &sdtCte.CteTomSer = Tomador.Outros Endif
//TEM RECEBEDOR OU EXPEDIDOR &sdtCte.CteTemExpRec = iif(CteExpCod > 0 or CteRecCod > 0, true, false)
//Cidade Origem DEstino &sdtCte.CteIniUfe = CteIniUfe &sdtCte.CteIniCidCod = CteIniCidCod &sdtCte.CteIniCidNom = CteIniCidNom //Cidade destino &sdtCte.CteTerUfe = CteTerUfe &sdtCte.CteTerCidCod = CteTerCidCod &sdtCte.CteTerCidNom = CteTerCidNom if CteModCod = '67' and (CteIniUfe.IsEmpty() or CteIniUfe.IsNull() or CteTerUfe.IsEmpty() or CteTerUfe.IsNull())
//Cidade Origem DEstino &sdtCte.CteIniUfe = FilCidUfeCod &sdtCte.CteIniCidCod = FilCidUfeIbge &sdtCte.CteIniCidNom = FilCidNom //Cidade destino &sdtCte.CteTerUfe = FilCidUfeCod &sdtCte.CteTerCidCod = FilCidUfeIbge &sdtCte.CteTerCidNom = FilCidNom Endif
//tem outra origem destino Do CAse CAse CteModCod = '67' &sdtCte.CteTemOriDes = true CAse (&sdtCte.CteIniCidCod <> &sdtCte.CteExpCidCod) and &sdtCte.CteExpCidCod> 0 and &sdtCte.CteExpCod > 0 &sdtCte.CteTemOriDes = true CAse (&sdtCte.CteTerCidCod <> &sdtCte.CteRecCidCod) and &sdtCte.CteRecCidCod > 0 and &sdtCte.CteRecCod > 0 &sdtCte.CteTemOriDes = true CAse (&sdtCte.CteIniCidCod <> &sdtCte.CteRemCidCod) and &sdtCte.CteExpCod = 0 &sdtCte.CteTemOriDes = true CAse (&sdtCte.CteTerCidCod <> &sdtCte.CteDesCidCod) and &sdtCte.CteRecCod = 0 &sdtCte.CteTemOriDes = true Otherwise &sdtCte.CteTemOriDes = false EndCAse
Exit When None &sdtCte.sts = 'J999' &sdtCte.obs = 'CTe não localizado' EndFor Else &sdtCte.sts = 'E999' &sdtCte.obs = 'Nada mais aqui!' return Endif
